const payload = $input.first().json;
const slots = payload.slots || [];
return slots.map((slot, index) => ({
  json: {
    option: String.fromCharCode(65 + (index % 26)),
    calendarId: 'DCLT Badminton Availability',
    summary: slot.title,
    start: { dateTime: slot.start, timeZone: payload.timezone || 'Europe/London' },
    end: { dateTime: slot.end, timeZone: payload.timezone || 'Europe/London' },
    location: slot.venue,
    description: [
      `Courts: ${(slot.courts || []).join(', ')}`,
      `Booking: ${slot.booking_url}`,
      `Checked: ${payload.checked_at}`,
      `Managed by: ${payload.manager}`,
      `Slot key: ${slot.id}`,
      'Note: API availability only; final booking/pricing not verified.'
    ].join('\n'),
    slotId: slot.id,
    bookingUrl: slot.booking_url,
    source: slot.source
  }
}));

const rows = $input.all().map(i => i.json);
return [{ json: {
  count: rows.length,
  telegramSummary: rows.length ? rows.map(r => `${r.option}. ${r.summary} ${r.start.dateTime.slice(11,16)}-${r.end.dateTime.slice(11,16)} (${(r.description.match(/^Courts: (.*)$/m)||[])[1] || ''})`).join('\n') : 'No available badminton slots found',
  events: rows
}}];

// Diff desired (from Build calendar event payloads) vs existing managed GCal events, keyed by Slot key.
const desired = $('Build calendar event payloads').all().map(i => i.json);
const existing = $('GCal: Get managed events').all().map(i => i.json);

const keyRe = /Slot key:\s*(\S+)/;
const existingByKey = {};
for (const ev of existing) {
  const m = (ev.description || '').match(keyRe);
  if (m) existingByKey[m[1]] = ev;
}
const desiredKeys = new Set(desired.map(d => d.slotId));

const out = [];
// create missing / update changed
for (const d of desired) {
  const ex = existingByKey[d.slotId];
  if (!ex) {
    out.push({ json: { _action: 'create', ...d } });
  } else {
    const changed =
      (ex.start && ex.start.dateTime) !== d.start.dateTime ||
      (ex.end && ex.end.dateTime) !== d.end.dateTime ||
      ex.summary !== d.summary ||
      ex.description !== d.description ||
      ex.location !== d.location;
    if (changed) out.push({ json: { _action: 'update', eventId: ex.id, ...d } });
  }
}
// delete stale managed events not in desired set
for (const ev of existing) {
  const m = (ev.description || '').match(keyRe);
  const key = m && m[1];
  if (key && !desiredKeys.has(key)) {
    out.push({ json: { _action: 'delete', eventId: ev.id, slotId: key } });
  }
}
return out;
